// === Check if a transaction ID is in the refundedTransactions array ===
// Mode: "Run Once for All Items".

const body = ($input.first()?.json ?? {}).body ?? {};

// 1) The ID to look for.
const targetId = String(body.transactionId ?? '').trim().toLowerCase();

// 2) The array to search.
const refunded = body.refundedTransactions ?? [];
const list = Array.isArray(refunded) ? refunded : [];

// 3) First element whose top-level id matches (provider.id is ignored).
const match = targetId
  ? list.find((el) => String(el?.id ?? '').trim().toLowerCase() === targetId)
  : undefined;

// 4) Output the decision (+ the matched element, for logging/branching).
return [{
  json: {
    targetId,
    found: !!match,
    matchedTransaction: match ?? null,
  },
}];

